// lib/posts.ts
import { unstable_cache } from "next/cache";

export interface Post {
  id: number;
  title: string;
  content: string;
  createdAt: string;
}

// In-memory store simulating a database
const posts: Post[] = [
  {
    id: 1,
    title: "Hello World",
    content: "This is the first post.",
    createdAt: "2026-07-01T00:00:00.000Z",
  },
  {
    id: 2,
    title: "Getting Started with Next.js",
    content: "Next.js is a React framework for production.",
    createdAt: "2026-07-05T00:00:00.000Z",
  },
];

export function getAllPosts(): Post[] {
  return [...posts];
}

export function createPost(title: string, content: string): Post {
  const post: Post = {
    id: posts.length + 1,
    title,
    content,
    createdAt: new Date().toISOString(),
  };
  posts.push(post);
  return post;
}

/**
 * Cached version of getAllPosts tagged with "posts".
 *
 * Once cached, the result is reused across requests until
 * revalidateTag("posts", "max") is called — at which point
 * the next invocation re-executes the callback for fresh data.
 *
 * The artificial delay makes cache hits vs. misses observable.
 */
export const getCachedPosts = unstable_cache(
  async () => {
    // Simulate a data-fetching delay so cache behavior is visible
    await new Promise((resolve) => setTimeout(resolve, 200));
    return getAllPosts();
  },
  ["posts-list"],
  { tags: ["posts"] }
);


